import math
class Solution:
    def maxScore(self, nums):
        n = len(nums)
        def pairings(items):
            if not items:
                yield []
                return
            a = items[0]
            for i in range(1, len(items)):
                b = items[i]
                rest = items[1:i] + items[i + 1:]
                for p in pairings(rest):
                    yield [(a, b)] + p
        best = 0
        for p in pairings(list(range(n))):
            gs = sorted(math.gcd(nums[i], nums[j]) for i, j in p)
            sc = sum((k + 1) * gs[k] for k in range(len(gs)))
            if sc > best:
                best = sc
        return best

