import math
from functools import lru_cache
class Solution:
    def maxScore(self, nums):
        n = len(nums)
        @lru_cache(maxsize=None)
        def dp(mask):
            taken = bin(mask).count('1')
            if taken == n:
                return 0
            op = taken // 2 + 1
            best = 0
            for i in range(n):
                if mask & (1 << i):
                    continue
                for j in range(i + 1, n):
                    if mask & (1 << j):
                        continue
                    nm = mask | (1 << i) | (1 << j)
                    cand = op * math.gcd(nums[i], nums[j]) + dp(nm)
                    if cand > best:
                        best = cand
            return best
        return dp(0)

