var maxScore = function(nums) {
    const n = nums.length;
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const memo = new Map();
    const dp = (mask) => {
        if (memo.has(mask)) return memo.get(mask);
        let taken = 0;
        for (let k = 0; k < n; k++) if (mask & (1 << k)) taken++;
        if (taken === n) { memo.set(mask, 0); return 0; }
        const op = ((taken / 2) | 0) + 1;
        let best = 0;
        for (let i = 0; i < n; i++) {
            if (mask & (1 << i)) continue;
            for (let j = i + 1; j < n; j++) {
                if (mask & (1 << j)) continue;
                const nm = mask | (1 << i) | (1 << j);
                const cand = op * gcd(nums[i], nums[j]) + dp(nm);
                if (cand > best) best = cand;
            }
        }
        memo.set(mask, best);
        return best;
    };
    return dp(0);
};
